# Flatten data into denomination,objet
xan from data/agora_repertoire_opendata.json.gz --root publications | xan select denomination,exercices | xan explode exercices -S -e '_.parse_json()' | xan explode exercice -e '_.parse_json().publicationCourante.activites || {}' | xan map 'exercice.parse_json().publicationCourante | [_.objet.try(), _.publicationDate.datetime("%d/%m/%Y à %H:%M:%S").try()] as (objet, date)' | xan search -s objet -N | xan drop exercice > objets.csv 

xan from data/agora_repertoire_opendata.json.gz --root publications | xan select denomination,exercices,codePostal,activites.listNiveauIntervention | xan explode exercices -S -e '_.parse_json()' | xan map 'exercice.parse_json().publicationCourante | [_.nombreSalaries, _.montantDepense, _.activites.len()] as (salaries, amount, activites)' | xan drop exercice | xan filter 'salaries && amount && activites > 0' | xan separate -krc amount --into lower_bound '(?:et )?< ([\d\s]+)' | xan transform lower_bound '_.replace(" ", "")'
